CREATE INDEX idx_anon_eval_drafts_responder ON public.anonymous_evaluation_drafts USING btree (responder_id);

CREATE INDEX idx_custom_eval_send_events_user ON public.custom_evaluation_send_events USING btree (user_id, created_at DESC);

CREATE INDEX idx_evaluation_drafts_evaluator ON public.evaluation_drafts USING btree (evaluator_id);

CREATE INDEX idx_export_history_user ON public.export_history USING btree (user_id, created_at DESC);

CREATE UNIQUE INDEX user_settings_pkey ON public.user_settings USING btree (user_id);

